// // This module toggles its output on the falling edge of the clock when the T input is low.
module TFlipFlop (  
    input clk,  
    input T,  
    input reset,  
    output reg Q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            Q <= 0;  
        end else if (T) begin  
            Q <= ~Q;  
        end  
    end  
endmodule
